import functools


def repeat(times):
    if times < 1:
        raise ValueError("times must be >= 1")

    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            result = None
            for _ in range(times):
                result = func(*args, **kwargs)
            return result

        return wrapper

    return decorator

tests.content:
import pytest

from solution import repeat


def test_calls_n_times_and_returns_last():
    calls = []

    @repeat(times=3)
    def f():
        calls.append(1)
        return len(calls)

    assert f() == 3, "must return the result of the final run"
    assert len(calls) == 3, "must call the wrapped function exactly `times` times"


def test_times_one_behaves_like_plain_call():
    @repeat(times=1)
    def double(x):
        return x * 2

    assert double(5) == 10


def test_forwards_args_on_every_run():
    seen = []

    @repeat(times=2)
    def f(a, b, *, c):
        seen.append((a, b, c))
        return a + b + c

    assert f(1, 2, c=3) == 6
    assert seen == [(1, 2, 3), (1, 2, 3)], "arguments must be forwarded on each run"


def test_preserves_metadata():
    @repeat(times=2)
    def documented():
        """Docs."""
        return 1

    assert documented.__name__ == "documented", "use functools.wraps on the inner wrapper"
    assert documented.__doc__ == "Docs."


def test_rejects_invalid_times_at_decoration_time():
    # Tricky: validation must happen in the factory, before a function exists.
    with pytest.raises(ValueError):
        repeat(times=0)

