import functools


def retry(times=3, exceptions=(Exception,)):
    if times < 1:
        raise ValueError("times must be >= 1")

    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            last_exc = None
            for _ in range(times):
                try:
                    return func(*args, **kwargs)
                except exceptions as exc:
                    # Only the configured exception types are retried; anything
                    # else propagates immediately (it is not caught here).
                    last_exc = exc
            raise last_exc

        return wrapper

    return decorator

tests.content:
import pytest

from solution import retry


def test_success_is_not_retried():
    calls = []

    @retry(times=5)
    def ok():
        calls.append(1)
        return "value"

    assert ok() == "value"
    assert len(calls) == 1, "a successful call must not be retried"


def test_uses_configured_attempt_count():
    state = {"n": 0}

    @retry(times=4)
    def boom():
        state["n"] += 1
        raise ValueError("x")

    with pytest.raises(ValueError):
        boom()
    assert state["n"] == 4, "must attempt exactly `times` times"


def test_default_times_is_three():
    state = {"n": 0}

    @retry()
    def boom():
        state["n"] += 1
        raise ValueError("x")

    with pytest.raises(ValueError):
        boom()
    assert state["n"] == 3, "default `times` must be 3"


def test_recovers_within_budget():
    state = {"n": 0}

    @retry(times=3)
    def flaky():
        state["n"] += 1
        if state["n"] < 3:
            raise ConnectionError("transient")
        return "ok"

    assert flaky() == "ok"
    assert state["n"] == 3


def test_only_retries_listed_exceptions():
    # Tricky: an exception not in `exceptions` must propagate on the first
    # attempt without consuming the remaining budget.
    state = {"n": 0}

    @retry(times=3, exceptions=(KeyError,))
    def f():
        state["n"] += 1
        raise ValueError("not retried")

    with pytest.raises(ValueError):
        f()
    assert state["n"] == 1, "a non-listed exception must not be retried"


def test_reraises_last_exception_instance():
    raised = []

    @retry(times=3)
    def f():
        exc = RuntimeError(f"attempt-{len(raised)}")
        raised.append(exc)
        raise exc

    with pytest.raises(RuntimeError) as info:
        f()
    assert str(info.value) == "attempt-2", "must re-raise the last attempt's exception"
    assert info.value is raised[-1]


def test_rejects_invalid_times_at_decoration_time():
    with pytest.raises(ValueError):
        retry(times=0)


def test_preserves_metadata():
    @retry(times=2)
    def documented():
        """Docs."""
        return 1

    assert documented.__name__ == "documented"
    assert documented.__doc__ == "Docs."

