import functools


def envelope(label):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            inner = func(*args, **kwargs)
            # Markers go around the inner result; stacking nests these lists,
            # so the outermost decorator's markers end up on the outside.
            return [f"<{label}>", *inner, f"</{label}>"]

        return wrapper

    return decorator

tests.content:
from solution import envelope


def test_single_layer():
    @envelope("a")
    def f():
        return ["core"]

    assert f() == ["<a>", "core", "</a>"]


def test_stacking_outer_wraps_inner():
    # @outer over @inner == outer(inner(f)): inner is applied first.
    @envelope("outer")
    @envelope("inner")
    def f():
        return ["core"]

    assert f() == ["<outer>", "<inner>", "core", "</inner>", "</outer>"]


def test_three_layers_nest_in_order():
    @envelope("a")
    @envelope("b")
    @envelope("c")
    def f():
        return ["x"]

    assert f() == ["<a>", "<b>", "<c>", "x", "</c>", "</b>", "</a>"]


def test_swapping_order_changes_nesting():
    # Tricky: same two decorators, swapped, produce a different result.
    @envelope("b")
    @envelope("a")
    def f():
        return ["x"]

    assert f() == ["<b>", "<a>", "x", "</a>", "</b>"]


def test_forwards_args_and_preserves_metadata():
    @envelope("a")
    def documented(seed):
        """Docs."""
        return [seed]

    assert documented("s") == ["<a>", "s", "</a>"]
    assert documented.__name__ == "documented"
    assert documented.__doc__ == "Docs."
